mapper.select:
SELECT r.id, r.prob_id AS probId, r.assignee, r.assignee_role AS assigneeRole, r.restore_status AS restoreStatus, r.office_code AS officeCode, r.create_time AS createTime, r.create_by AS createBy, m.probNum, m.theme, d.departmentName AS officeName, u.realName AS assigneeName FROM prob_restore r LEFT JOIN prob_main m ON r.prob_id = m.id LEFT JOIN fnd_department d ON r.office_code = d.departmentNum AND d.status = 1 LEFT JOIN fnd_user_info u ON r.assignee = u.username AND u.status = 1 WHERE r.effective_to IS NULL
AND r.prob_id = #{params.probId}
AND r.assignee = #{params.assignee}
AND r.restore_status = #{params.restoreStatus}
AND r.assignee_role = #{params.assigneeRole}
AND r.office_code IN (${params.areapower})
ORDER BY r.create_time DESC
LIMIT #{params.offset}, #{params.pageSize}
